import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import ProjectList from '../components/Projects/ProjectList';
import TaskList from '../components/Tasks/TaskList';
import { useAuth } from '../context/AuthContext';

const Dashboard = () => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);

  // Load user's projects and tasks
  useEffect(() => {
    const fetchUserData = async () => {
      try {
        // In a real app, you would fetch this data from your API
        // For demo purposes, we'll use mock data
        const userProjects = [
          { 
            id: 1, 
            name: 'My First Project', 
            description: 'Your first project',
            color: '#4299e1',
            userId: currentUser.id
          }
        ];

        const userTasks = [
          {
            id: 1,
            title: 'Complete onboarding',
            description: 'Finish setting up your account',
            status: 'Not Started',
            due_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
            project_id: 1,
            assignee_id: currentUser.id,
            created_at: new Date().toISOString()
          }
        ];

        setProjects(userProjects);
        setTasks(userTasks);
        setLoading(false);
      } catch (error) {
        console.error('Error fetching user data:', error);
        setLoading(false);
      }
    };

    if (currentUser) {
      fetchUserData();
    }
  }, [currentUser]);

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loader">Loading your dashboard...</div>
      </div>
    );
  }

  const stats = {
    totalProjects: projects.length,
    totalTasks: tasks.length,
    completedTasks: tasks.filter(task => task.status === 'Completed').length,
    inProgressTasks: tasks.filter(task => task.status === 'In Progress').length,
    myTasks: tasks.filter(task => task.assignee_id === currentUser.id).length
  };

  const recentTasks = [...tasks]
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
    .slice(0, 5);

  const myRecentTasks = tasks
    .filter(task => task.assignee_id === currentUser.id)
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
    .slice(0, 3);

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Welcome to TaskTrail, {currentUser.name}! 👋</h1>
        <p>Here's what's happening with your projects today.</p>
      </div>

      {/* Statistics Grid */}
      <div className="stats-grid">
        <div className="stat-card" onClick={() => navigate('/projects')}>
          <h3>{stats.totalProjects}</h3>
          <p>Total Projects</p>
        </div>
        <div className="stat-card" onClick={() => navigate('/tasks')}>
          <h3>{stats.totalTasks}</h3>
          <p>Total Tasks</p>
        </div>
        <div className="stat-card" onClick={() => navigate('/tasks?status=in-progress')}>
          <h3>{stats.inProgressTasks}</h3>
          <p>In Progress</p>
        </div>
        <div className="stat-card" onClick={() => navigate('/tasks?assignee=me')}>
          <h3>{stats.myTasks}</h3>
          <p>My Tasks</p>
        </div>
      </div>

      <div className="dashboard-content">
        {/* Recent Tasks */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Recent Tasks</h2>
            <button 
              className="view-all"
              onClick={() => navigate('/tasks')}
            >
              View All
            </button>
          </div>
          <TaskList 
            tasks={myRecentTasks} 
            projects={projects}
            users={[currentUser]}
          />
        </section>

        {/* Projects */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Projects</h2>
            <button 
              className="view-all"
              onClick={() => navigate('/projects')}
            >
              View All
            </button>
          </div>
          <ProjectList 
            projects={projects} 
            tasks={tasks}
          />
        </section>
      </div>
    </div>
  );
};

export default Dashboard;
